#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=1e6+5;
int n,m,k,c[maxn],ans=LLONG_MAX,cnt;
struct ff {
	int u,v,w,p;
} e[maxn];
bool cmp(ff a,ff b) {
	return a.w<b.w;
}
void zz(int u,int v,int w,int p) {
	cnt++;
	e[cnt]= {u,v,w,p};
}
int fu[maxn],cd[maxn];
void d() {
	for(int i=1; i<=n; i++) {
		fu[i]=i;
		cd[i]=1;
	}
	for(int i=1; i<=k; i++) {
		fu[i+n]=i+n;
	}
}
int xz(int x) {
	if(fu[x]==x) {
		return x;
	}
	return fu[x]=xz(fu[x]);
}
void aaa(int x,int y) {
	int ax=xz(x),ay=xz(y);
	fu[xz(x)]=ay;
	cd[ay]+=cd[ax];
	cd[ax]=0;
}
int ss[maxn];
void slove() {
	d();
	int sum=0;
	for(int i=1; i<=k; i++) {
		if(ss[i]) {
			sum+=c[i];
		}
	}
	for(int i=1; i<=cnt; i++) {
		int ax=xz(e[i].u),ay=xz(e[i].v);
		if(ax==ay||!ss[e[i].p]) {
			continue;
		}
		fu[ax]=ay;
		cd[ay]+=cd[ax];
		cd[ax]=0;
		sum+=e[i].w;
		if(cd[ay]==n) {
			ans=min(ans,sum);
			return;
		}
	}
}
void dfs(int ii) {
	if(ii>k) {
		slove();
		return;
	}
	ss[ii]=1;
	dfs(ii+1);
	ss[ii]=0;
	dfs(ii+1);
	return;
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m>>k;
	for(int i=1; i<=m; i++) {
		int u,v,w;
		cin>>u>>v>>w;
		zz(u,v,w,0);
	}
	for(int i=1; i<=k; i++) {
		cin>>c[i];
		for(int j=1; j<=n; j++) {
			int xx;
			cin>>xx;
			zz(i+n,j,xx,i);
		}
	}
	sort(e+1,e+1+cnt,cmp);
	ss[0]=1;
	dfs(1);
	cout<<ans;
	return 0;
}
